// Track timers/intervals scheduled by the welcome-content chain so we can cancel
// them in cleanupScript when IndexPage unmounts. Without this, setTimeouts fire
// against DOM elements that are already gone and throw null-pointer errors.
const trackedTimers = new Set();
const trackedIntervals = new Set();
// Hidden <video>s that preloadVideos() appends to <body>. Tracked so cleanupScript
// can remove them on unmount; left behind they keep playing and, on iOS, can surface
// as a fullscreen player over other pages.
const preloadedVideos = [];

function trackedSetTimeout(fn, delay) {
    const id = setTimeout(() => {
        trackedTimers.delete(id);
        fn();
    }, delay);
    trackedTimers.add(id);
    return id;
}

function trackedSetInterval(fn, delay) {
    const id = setInterval(fn, delay);
    trackedIntervals.add(id);
    return id;
}

export function initScript() {
    if (window.location.hash === '#/home') { // Check if the current page is not the homepage
        document.querySelectorAll('header *').forEach(element => {
            element.style.color = '';
        });
        document.querySelectorAll('footer *').forEach(element => {
            element.style.color = '';
        });
    }
    function onDOMContentLoaded() {
        console.log('DOM fully loaded and parsed');
        // Your script logic here
        let shakeQueue = [];
        let isShaking = false;
        let pressCount = 0;
        let pressed = false;
        let resetTimeout;
        const maxAngle = 360; // Maximum angle to prevent excessive shaking
        const minDuration = 0.2; // Minimum duration to prevent excessive speed
    
        let canPlayVideo = true;
        let navigating = false; // true once a compass click starts the shake-then-go to Journey
    
        let currentTimeoutId; // Variable to store the current timeout ID
    
        const videoSources = [
            { src: "/assets/vid/home1.mp4", class: "homevideo1", description: "Sunbathing, beers, and ocean breezes, shot on the Mediterranean sea." },
            // { src: "/assets/vid/home2.mp4", class: "homevideo2", description: "Ducks enjoying a swim by the oceanside, weaving between the boats." },
            { src: "/assets/vid/home3.mp4", class: "homevideo3", description: "A cat strolling on the ancient stone steps, shot in Athens, Greece." },
            // { src: "/assets/vid/home4.mp4", class: "homevideo4", description: "Travelling through clouds at sunset, shot on a trip from Sydney to Melbourne." },
            { src: "/assets/vid/home5.mp4", class: "homevideo5", description: "Pied Cormorants resting on a sea cliff, shot in Warrnambool, Australia." },
        ];
    
        let nonPlayed = [...videoSources];
    
        let currentVideoSource = videoSources[0];

        function pickNextVideoSource(currentSrc) {
            const isCurrent = (source) => source.src === currentSrc;
            let candidates = nonPlayed.filter(source => !isCurrent(source));

            if (candidates.length === 0) {
                nonPlayed = videoSources.filter(source => !isCurrent(source));
                candidates = [...nonPlayed];
            }

            if (candidates.length === 0) {
                return videoSources[0];
            }

            const selected = candidates[Math.floor(Math.random() * candidates.length)];
            nonPlayed = nonPlayed.filter(source => source.src !== selected.src);
            return selected;
        }
    
        function isMobilePhone() {
            const userAgent = navigator.userAgent || navigator.vendor || window.opera;
            return /android|iPhone|iPod/i.test(userAgent);
        }
    
        function isTouchScreen(){
            const userAgent = navigator.userAgent || navigator.vendor || window.opera;
            return /android|iPhone|iPad|iPod/i.test(userAgent);
        }
    
        function changeVideoSource() {
            const videoElement = document.getElementById('videoElement');
            const currentSourceElement = videoElement.querySelector('source');
            const currentSource = currentSourceElement.getAttribute('src');
            const source = pickNextVideoSource(currentSource);
            currentVideoSource = source;

            currentSourceElement.setAttribute('src', source.src)
            videoElement.setAttribute('class', source.class);
            videoElement.load();
    
            // Update the description content
            const descriptionContentElement = document.getElementById('descriptionContent');
            descriptionContentElement.innerHTML = `${source.description}<br><p>Click for color and sound!</p>`;
        }
    
        function preloadVideos() {
            videoSources.forEach(videoData => {
                const video = document.createElement('video');
                video.src = videoData.src;
                video.preload = 'auto';
                video.autoplay = true;
                video.loop = true;
                video.muted = true;
                // iOS forces inline videos that lack these attributes into the native
                // fullscreen player. These hidden autoplay clips were doing exactly that
                // on phones; keep them inline so they only warm the cache.
                video.playsInline = true;
                video.setAttribute('playsinline', '');
                video.setAttribute('webkit-playsinline', '');
                video.style.display = 'none'; // Hide the video element
                document.body.appendChild(video);
                preloadedVideos.push(video);
            });
        }
    
        function updateSubtitle() {
            const subtitleElement = document.getElementById('welcomeSubtitle');
            const isMobile = window.matchMedia("(max-width: 768px)").matches;
    
            if (isMobile) {
                subtitleElement.textContent = "Hi, I'm Henry, a senior at HKU. I like to explore and notice the small things. Glad you wandered in, take your time and look around.";
            } else {
                subtitleElement.textContent = "Hi, I'm Henry, a senior at HKU. I like wandering into new places and noticing the small things most people walk past. Glad you're here, take a look around.";
            }
        }
    
        function getTextWidth(text, font) {
            const canvas = getTextWidth.canvas || (getTextWidth.canvas = document.createElement("canvas"));
            const context = canvas.getContext("2d");
            context.font = font;
            const metrics = context.measureText(text);
            return metrics.width;
        }
    
        function getCssStyle(element, prop) {
            return window.getComputedStyle(element, null).getPropertyValue(prop);
        }
    
        function getCanvasFont(el) {
            const fontWeight = getCssStyle(el, 'font-weight') || 'normal';
            const fontSize = getCssStyle(el, 'font-size') || '16px';
            const fontFamily = getCssStyle(el, 'font-family') || 'Times New Roman';
            return `${fontWeight} ${fontSize} ${fontFamily}`;
        }
    
        function adjustTitle() {
            const videoElement = document.getElementById('videoElement');
            const imageElement = document.getElementById('imageElement');
            const titleElement = document.getElementById('welcomeTitle');
            const subtitleElement = document.getElementById('welcomeSubtitle');
            const compassIcon = document.getElementById('compassIcon');
    
            const mediaElement = videoElement.style.display !== 'none' ? videoElement : imageElement;
            const mediaHeight = mediaElement.clientHeight;
            const availableWidth = document.querySelector('.welcome-text').clientWidth;
    
            // Adjust the font size and line height of the title to fit the width
            let titleFontSize = 1; // Start with a smaller font size
            titleElement.style.fontSize = `${titleFontSize}em`;
            
            let iconScaleFactor = 0.3; // Scale factor to adjust the icon size relative to the text
            compassIcon.style.fontSize = `${titleFontSize * iconScaleFactor}em`;
            
            let textWidth = getTextWidth(titleElement.textContent.replace('O', ''), getCanvasFont(titleElement)) + compassIcon.clientWidth;
            while (textWidth < availableWidth && titleFontSize < 5) { // Constrain max font size to 5em
                titleFontSize += 0.1;
                titleElement.style.fontSize = `${titleFontSize}em`;
                compassIcon.style.fontSize = `${titleFontSize * iconScaleFactor}em`;
                textWidth = getTextWidth(titleElement.textContent.replace('O', ''), getCanvasFont(titleElement)) + compassIcon.clientWidth;
            }
    
            while (textWidth > availableWidth && titleFontSize > 0.5) { // Constrain min font size to 0.5em
                titleFontSize -= 0.1;
                titleElement.style.fontSize = `${titleFontSize}em`;
                compassIcon.style.fontSize = `${titleFontSize * iconScaleFactor}em`;
                textWidth = getTextWidth(titleElement.textContent.replace('O', ''), getCanvasFont(titleElement)) + compassIcon.clientWidth;
            }
        }
    
        function adjustSubtitle() {
            const videoElement = document.getElementById('videoElement');
            const imageElement = document.getElementById('imageElement');
            const titleElement = document.getElementById('welcomeTitle');
            const subtitleElement = document.getElementById('welcomeSubtitle');
            const compassIcon = document.getElementById('compassIcon');
    
            const mediaElement = videoElement.style.display !== 'none' ? videoElement : imageElement;
            const mediaHeight = mediaElement.clientHeight;
            const availableWidth = document.querySelector('.welcome-text').clientWidth;
    
            // Fix the title font size and adjust the subtitle to match the height of the video
            let subtitleFontSize = 1;
            subtitleElement.style.fontSize = `${subtitleFontSize}em`;
            let totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
    
            while (totalHeight < mediaHeight && subtitleFontSize < 3) { // Constrain max font size to 3em
                subtitleFontSize += 0.01;
                subtitleElement.style.fontSize = `${subtitleFontSize}em`;
                totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
            }
    
            // Reduce font size and line height if the total height exceeds the video height
            while (totalHeight > mediaHeight && subtitleFontSize > 0.5) { // Ensure font size does not go below 0.5em
                subtitleFontSize -= 0.01;
                subtitleElement.style.fontSize = `${subtitleFontSize}em`;
                totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
            }
    
            // Adjust the line height of the subtitle element to fit within the media height
            let subtitleLineHeight = 1.4; // Starting line height
            subtitleElement.style.lineHeight = subtitleLineHeight;
            totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
    
            while (totalHeight < mediaHeight && subtitleLineHeight < 2) { // Constrain max line height to 2
                subtitleLineHeight += 0.1;
                subtitleElement.style.lineHeight = subtitleLineHeight;
                totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
            }
    
            while (totalHeight > mediaHeight && subtitleLineHeight > 1) { // Ensure line height does not go below 1
                subtitleLineHeight -= 0.1;
                subtitleElement.style.lineHeight = subtitleLineHeight;
                totalHeight = titleElement.clientHeight + subtitleElement.clientHeight;
            }
        }
    
        function updateTitles() {
            updateSubtitle();
            adjustTitle();
            const isMedScreen = window.matchMedia("(max-width: 600px)").matches;
            if (isMedScreen) {
                document.getElementById('welcomeTitle').style.fontSize = '2em';
                document.getElementById('compassIcon').style.fontSize = '1.1em';
            }
            const isSmallScreen = window.matchMedia("(max-width: 400px)").matches;
            if (isSmallScreen) {
                document.getElementById('welcomeTitle').style.fontSize = '1.8em';
                document.getElementById('compassIcon').style.fontSize = '1.1em';
            }
            adjustSubtitle();
        }
    
        function typeWriterEffect(text, element, delay = 100, callback) {
            // Clear any existing timeout to interrupt the previous typing effect
            if (currentTimeoutId) {
                clearTimeout(currentTimeoutId);
            }
    
            element.innerHTML = '';
            let index = 0;
            const spans = [];
    
            // Step 1: Create a span for each character
            for (let i = 0; i < text.length; i++) {
                const span = document.createElement('span');
                span.className = 'typed';
                span.style.color = 'transparent'; // Initially transparent
                span.textContent = text[i];
                element.appendChild(span);
                spans.push(span);
            }
    
            // Step 2: Turn each span into the text color one by one
            function reveal() {
                if (index < spans.length) {
                    const isDarkMode = document.body.classList.contains('dark-mode');
                    const textColor = isDarkMode ? '#fafafa' : '#252525'; // Change text color based on theme
                    
                    spans[index].style.transition = `color 2s`;
                    spans[index].style.color = textColor;
                    index++;
                    currentTimeoutId = setTimeout(reveal, delay); // Store the timeout ID
                } else {
                    if (callback) callback();
                }
            }
    
            reveal();
        }
    
        function videoTransition() {
            // The grey overlay used to fade in near the end of each clip to mask the
            // loop seam. Clips no longer loop — they auto-advance, and the flip hides
            // the swap at its edge-on midpoint — so keep the overlay transparent and
            // hand straight off to the next clip with no fade-to-grey.
            const transitionOverlay = document.getElementById('transitionOverlay');
            transitionOverlay.style.opacity = '0';
        }
    
        function processShakeQueue() {
            if (shakeQueue.length === 0 || isShaking) return;
            
            isShaking = true;
            const { newAngle, newDuration } = shakeQueue.shift();
            
            const compassIcon = document.getElementById('compassIcon');
            compassIcon.style.setProperty('--shake-angle', `${newAngle}deg`);
            compassIcon.style.setProperty('--shake-duration', `${newDuration}s`);
            
            compassIcon.classList.add('shake');
            
            setTimeout(() => {
                compassIcon.classList.remove('shake');
                isShaking = false;
                processShakeQueue(); // Process the next shake in the queue
            }, newDuration * 1000);
        }
    
        function switchVideoSource() {
            const videoElement = document.getElementById('videoElement');
            const transitionOverlay = document.getElementById('transitionOverlay');
            const descriptionOverlay = document.getElementById('descriptionOverlay');
            const frameContainer = videoElement.closest('.image-left.container');
            const currentSourceElement = videoElement.querySelector('source');
            const currentSource = currentSourceElement.getAttribute('src');
    
            const newVideoSource = pickNextVideoSource(currentSource);
            currentVideoSource = newVideoSource;
    
            // Apply flip effect. Keep the black description overlay out of the
            // 3D flip; when it rotates edge-on it can flash as a dark strip.
            if (frameContainer) frameContainer.classList.add('is-video-flipping');
            descriptionOverlay.style.opacity = '0';
            descriptionOverlay.classList.remove('flip', 'flip2');
            videoElement.classList.remove('flip2');
            videoElement.classList.add('flip');
            transitionOverlay.classList.remove('flip2');
            transitionOverlay.classList.add('flip');
    
            // Listen for the midpoint of the flip to change the source
            videoElement.addEventListener('animationend', () => {
                // Change the source and load the new video
                videoElement.pause(); // Pause the video before changing the source
                videoElement.querySelector('source').src = newVideoSource.src;
                videoElement.load(); // Load the new video source

                // Restart the flip animation for the second half of the transition
                videoElement.classList.remove('flip');
                transitionOverlay.classList.remove('flip');

                // Play the new video source. load() internally aborts any pending play,
                // so the returned promise can reject with
                // "play() was interrupted by a call to pause()". That's expected; swallow it.
                const playPromise = videoElement.play();
                if (playPromise && typeof playPromise.catch === 'function') {
                    playPromise.catch(() => {});
                }
    
                const descriptionContentElement = document.getElementById('descriptionContent');
                const hint = videoElement.muted ? 'Click for color and sound!' : 'Click to silence and fade!';
                descriptionContentElement.innerHTML = `${currentVideoSource.description}<br><p>${hint}</p>`;

                // Complete the flip's second half. The first half left the video edge-on
                // at rotateY(90deg) (zero projected width, so invisible); we hold there
                // until the new clip can actually paint a frame, otherwise flip2 would
                // rotate in a frameless <video> that briefly renders black. A short
                // timeout is the backstop so a slow decode never stalls the flip.
                const startSecondHalf = () => {
                    videoElement.classList.add('flip2');
                    transitionOverlay.classList.add('flip2');
                    videoElement.addEventListener('animationend', () => {
                        videoElement.classList.remove('flip2');
                        transitionOverlay.classList.remove('flip2');
                        videoElement.setAttribute('class', newVideoSource.class);
                        if (frameContainer) frameContainer.classList.remove('is-video-flipping');
                        descriptionOverlay.style.opacity = (!isTouchScreen() && videoElement.matches(':hover')) ? '0.5' : '';
                    }, { once: true });
                };
                if (videoElement.readyState >= 2) {
                    startSecondHalf();
                } else {
                    let kicked = false;
                    let fallback;
                    const go = () => {
                        if (kicked) return;
                        kicked = true;
                        clearTimeout(fallback);
                        videoElement.removeEventListener('loadeddata', go);
                        startSecondHalf();
                    };
                    videoElement.addEventListener('loadeddata', go, { once: true });
                    fallback = setTimeout(go, 450);
                }
            }, { once: true });
        }

        function createHint() {
            // Create a new <small> element
            var hintParagraph = document.createElement("small");
    
            // Set the class and style of the new <p> element
            hintParagraph.id = "hint";
            hintParagraph.className = "tipcolor-2";
            hintParagraph.style.float = "right";
    
            // Set the text content of the new element
            hintParagraph.textContent = 'Click the compass!';
    
            // Find the element with the class "header"
            var headerElement = document.querySelector(".header-title");
    
            // Append the new <p> element to the header element
            if (headerElement) {
                headerElement.insertBefore(hintParagraph, headerElement.children[2] || null);
            }
        }
    
        function compassFlash() {
            const compassIcon = document.getElementById('compassIcon');
            if (!compassIcon) return; // Component may have unmounted before this setTimeout fired
            compassIcon.style.transition = 'color 1.5s';

            function toggleTipColor() {
                if (!document.getElementById('compassIcon')) return;
                compassIcon.classList.add("tipcolor-1");
                trackedSetTimeout(function() {
                    if (!document.getElementById('compassIcon')) return;
                    compassIcon.classList.remove("tipcolor-1");
                }, 800);
            }

            const hintFlash = trackedSetInterval(function() {
                if (!document.getElementById('compassIcon')) {
                    clearInterval(hintFlash);
                    trackedIntervals.delete(hintFlash);
                    return;
                }
                if (!pressed) {
                    toggleTipColor();
                } else {
                    clearInterval(hintFlash);
                    trackedIntervals.delete(hintFlash);
                }
            }, 2400);
        }
    
        function displayWelcomeContent() {
            const titleElement = document.getElementById('welcomeTitle');
            const subtitleElement = document.getElementById('welcomeSubtitle');
            if (!titleElement || !subtitleElement) return;
            function dispatchHomeAskReady() {
                trackedSetTimeout(() => {
                    window.dispatchEvent(new CustomEvent('home-ask-ready'));
                }, 2000);
            }
            titleElement.style.transition = 'color 2s';
            titleElement.style.color = ''; // Reset to original color
            const subtitleText = subtitleElement.textContent;
            subtitleElement.style.textAlign = 'justify';
            subtitleElement.style.textAlignLast = 'justify';
            subtitleElement.style.MozTextAlignLast = 'justify';

            typeWriterEffect(subtitleText, subtitleElement, 10, () => {
                trackedSetTimeout(() => {
                    document.querySelectorAll('header *').forEach(element => {
                        element.style.transition = 'color 2s';
                        element.style.color = '';
                    });
                    document.querySelectorAll('footer *').forEach(element => {
                        element.style.transition = 'color 2s';
                        element.style.color = '';
                    });
                    const quoteElement = document.getElementById('welcomeQuote');
                    if (quoteElement) {
                        quoteElement.style.transition = 'color 2s';
                        quoteElement.style.color = '';
                    }
                    const homeAskElement = document.getElementById('homeAsk');
                    if (homeAskElement) {
                        homeAskElement.style.transition = 'color 2s';
                        homeAskElement.style.color = '';
                        dispatchHomeAskReady();
                    }

                    const overlay = document.getElementById('overlay');
                    if (overlay) overlay.style.pointerEvents = 'none';

                    trackedSetTimeout(() => {
                        compassFlash();

                        trackedSetTimeout(() => {
                            document.querySelectorAll('header *').forEach(element => {
                                element.style.transition = 'color 0.5s';
                            });
                            document.querySelectorAll('footer *').forEach(element => {
                                element.style.transition = 'color 0.5s';
                            });
                        }, 2000);
                    }, 1000);
                }, 1000);
            });
        }
    
        function setupDescriptionOverlay() {
            const videoElement = document.getElementById('videoElement');
            const descriptionOverlay = document.querySelector('.description-overlay');
    
            if (!isTouchScreen()) {
                videoElement.addEventListener('mouseenter', () => {
                    descriptionOverlay.style.opacity = '0.5';
                });
    
                videoElement.addEventListener('mouseleave', () => {
                    descriptionOverlay.style.opacity = '0';
                });
            }
        }
    
        document.getElementById('compassIcon').addEventListener('click', function() {

            if (navigating) return; // one click is enough; ignore the rest while it settles
            navigating = true;

            pressed = true;
            const compassIcon = document.getElementById('compassIcon');
            compassIcon.classList.remove("tipcolor-1");
            compassIcon.classList.remove("tipcolor-2");

            // Give the compass a single shake, then sail over to the Journey page
            // once that wobble has finished.
            const newAngle = 22;
            const newDuration = 0.7;
            shakeQueue.push({ newAngle, newDuration });
            processShakeQueue();

            setTimeout(() => {
                window.location.hash = '#/travels';
            }, newDuration * 1000);
        });
    
        if (window.location.hash === '#/home') { // Check if the current page is not the homepage
            const overlay = document.getElementById('overlay');
            overlay.style.pointerEvents = 'none'; // Disable pointer events to allow clicks
        }
    
        changeVideoSource();
    
        const videoElement = document.getElementById('videoElement');
        const fallbackImage = document.getElementById('imageElement');
        videoElement.style.opacity = '1';
        // Auto-advance: each clip plays once, then flips to the next (the flip used to be
        // triggered by clicking the compass). Registered once here — `loadeddata` refires on
        // every source swap, so registering it there would stack duplicate listeners.
        videoElement.addEventListener('ended', () => {
            if (canPlayVideo && !navigating) switchVideoSource();
        });
        // Function to handle video playback and related tasks
        function handleVideoPlayback() {
            // Create a flag to indicate whether the video is loaded successfully
            let videoLoaded = false;
            // Guards: ensure displayWelcomeContent runs exactly once per mount,
            // and prevent the success path from racing the fallback path on slow connections.
            let welcomeShown = false;
            let fallbackEngaged = false;

            function showWelcomeOnce() {
                if (welcomeShown) return;
                welcomeShown = true;
                displayWelcomeContent();
            }

            // Create a timeout to handle the scenario where loadeddata is not fired within 4 seconds
            const loadTimeout = setTimeout(() => {
                if (!videoLoaded) {
                    handleVideoError(new Error('Timeout waiting for video to load'));
                }
            }, 2000); // 2 seconds

            // Function to handle video errors
            function handleVideoError(error) {
                if (fallbackEngaged) return;
                fallbackEngaged = true;
                console.error('Error:', error);
                canPlayVideo = false;
                videoElement.style.display = 'none';
                fallbackImage.style.display = 'block';
                fallbackImage.style.opacity = '1';
                const checkDimensions = setInterval(function() {
                    if (imageElement.naturalWidth > 0 && imageElement.naturalHeight > 0) {
                        const aspectRatio = imageElement.naturalWidth / imageElement.naturalHeight;
                        // Check if the aspect ratio is approximately 9:16
                        if (Math.abs(aspectRatio - (9 / 16)) < 0.01) {
                            clearInterval(checkDimensions);

                            updateTitles();

                            setTimeout(() => {
                                showWelcomeOnce();
                            }, 1000);
                        }
                    }
                }, 100); // Check every 100ms until dimensions are available
            }

            // Listen for the loadeddata event to ensure the video is ready
            videoElement.addEventListener('loadeddata', () => {
                videoLoaded = true;
                clearTimeout(loadTimeout); // Clear the timeout since the video is loaded
                // If the fallback already kicked in (slow network beat the 2s deadline),
                // don't let the success path also show / restart the welcome content.
                if (fallbackEngaged) return;

                // Attempt to play the video
                videoElement.play().then(() => {
                    const checkDimensions = setInterval(function() {
                        if (videoElement.videoWidth > 0 && videoElement.videoHeight > 0) {
                            const aspectRatio = videoElement.videoWidth / videoElement.videoHeight;
                            // Check if the aspect ratio is approximately 9:16
                            if (Math.abs(aspectRatio - (9 / 16)) < 0.01) {
                                clearInterval(checkDimensions);

                                // createHint();
                                setupDescriptionOverlay();
                                updateTitles();

                                videoElement.addEventListener('click', () => {
                                    if (videoElement.muted) {
                                        videoElement.muted = false;
                                        videoElement.style.filter = 'grayscale(0%)';
                                        // Update the description content
                                        const descriptionContentElement = document.getElementById('descriptionContent');
                                        descriptionContentElement.innerHTML = `${currentVideoSource.description}<br><p>Click to silence and fade!</p>`;
                                    } else {
                                        videoElement.muted = true;
                                        videoElement.style.filter = 'grayscale(85%)';
                                        // Update the description content
                                        const descriptionContentElement = document.getElementById('descriptionContent');
                                        descriptionContentElement.innerHTML = `${currentVideoSource.description}<br><p>Click for color and sound!</p>`;
                                    }
                                });
    
                                preloadVideos();
                                videoTransition();

                                setTimeout(() => {
                                    showWelcomeOnce();
                                }, 1000);
                            }
                        }
                    }, 100); // Check every 100ms until dimensions are available
                }).catch((error) => {
                    // Handle errors that occur during video playback
                    handleVideoError(error);
                });
            }, { once: true });
    
            // Initial video load attempt
            try {
                videoElement.load();
            } catch (error) {
                handleVideoError(error);
            }
        }
    
        // Call the function to handle video playback
        handleVideoPlayback();
    
        // Debounced resize: mobile address-bar collapse fires resize repeatedly during scroll;
        // running the whole reflow each time killed the in-progress typing and felt janky.
        let resizeDebounce;
        window.onresize = () => {
            clearTimeout(resizeDebounce);
            resizeDebounce = setTimeout(() => {
                updateTitles();
                const isDarkMode = document.body.classList.contains('dark-mode');
                const subtitleElement = document.getElementById('welcomeSubtitle');
                const textColor = isDarkMode ? '#fafafa' : '#252525';
                subtitleElement.style.transition = 'color 0s';
                subtitleElement.style.color = textColor;
                subtitleElement.style.transition = '';
                subtitleElement.style.textAlign = 'justify';
                subtitleElement.style.textAlignLast = 'justify';
                subtitleElement.style.MozTextAlignLast = 'justify';
                document.querySelectorAll('header *').forEach(element => {
                    element.style.transition = 'color 2s';
                    element.style.color = '';
                });
                document.querySelectorAll('footer *').forEach(element => {
                    element.style.transition = 'color 2s';
                    element.style.color = '';
                });
                const quoteElement = document.getElementById('welcomeQuote');
                if (quoteElement) {
                    quoteElement.style.transition = 'color 2s';
                    quoteElement.style.color = '';
                }
                const homeAskElement = document.getElementById('homeAsk');
                if (homeAskElement) {
                    homeAskElement.style.transition = 'color 2s';
                    homeAskElement.style.color = '';
                }

                const overlay = document.getElementById('overlay');
                overlay.style.pointerEvents = 'none';
            }, 200);
        };
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', onDOMContentLoaded);
    } else {
        // The DOMContentLoaded event has already fired
        onDOMContentLoaded();
    }
}

// Called by IndexPage.vue's unmounted(). Clears pending timers from the welcome-content
// chain (so they don't fire against null DOM elements and throw) and the window-level
// resize handler initScript installed.
export function cleanupScript() {
    trackedTimers.forEach(clearTimeout);
    trackedTimers.clear();
    trackedIntervals.forEach(clearInterval);
    trackedIntervals.clear();
    // Tear down the hidden preload <video>s appended to <body>. Left in place they
    // keep playing after the homepage unmounts and, on iOS, can surface as a
    // fullscreen video over other pages.
    preloadedVideos.forEach(video => {
        try {
            video.pause();
            video.removeAttribute('src');
            video.load();
            video.remove();
        } catch (e) { /* element already gone */ }
    });
    preloadedVideos.length = 0;
    if (typeof window !== 'undefined') {
        window.onresize = null;
    }
}
